import heapq

class ProcessScheduler:
    def __init__(self):
        self.ready_queue = []  # min-heap by priority

    def add_process(self, priority, pid, process):
        heapq.heappush(self.ready_queue, (priority, pid, process))

    def schedule_next(self):
        if self.ready_queue:
            priority, pid, process = heapq.heappop(self.ready_queue)
            return process
        return None
